//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagekafkaimport("context""fmt""time""github.com/aws/aws-sdk-go/aws""github.com/aws/aws-sdk-go/service/kafka""github.com/hashicorp/terraform-plugin-sdk/v2/helper/retry""github.com/hashicorp/terraform-provider-aws/internal/tfresource")const(configurationDeletedTimeout=5*time.Minute)funcwaitClusterCreated(ctxcontext.Context,conn*kafka.Kafka,arnstring,timeouttime.Duration)(*kafka.Cluster,error){stateConf:=&retry.StateChangeConf{Pending:[]string{kafka.ClusterStateCreating},Target:[]string{kafka.ClusterStateActive},Refresh:statusClusterState(ctx,conn,arn),Timeout:timeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*kafka.Cluster);ok{ifstate,stateInfo:=aws.StringValue(output.State),output.StateInfo;state==kafka.ClusterStateFailed&&stateInfo!=nil{tfresource.SetLastError(err,fmt.Errorf("%s:%s",aws.StringValue(stateInfo.Code),aws.StringValue(stateInfo.Message)))}returnoutput,err}returnnil,err}funcwaitClusterDeleted(ctxcontext.Context,conn*kafka.Kafka,arnstring,timeouttime.Duration)(*kafka.Cluster,error){stateConf:=&retry.StateChangeConf{Pending:[]string{kafka.ClusterStateDeleting},Target:[]string{},Refresh:statusClusterState(ctx,conn,arn),Timeout:timeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*kafka.Cluster);ok{ifstate,stateInfo:=aws.StringValue(output.State),output.StateInfo;state==kafka.ClusterStateFailed&&stateInfo!=nil{tfresource.SetLastError(err,fmt.Errorf("%s:%s",aws.StringValue(stateInfo.Code),aws.StringValue(stateInfo.Message)))}returnoutput,err}returnnil,err}funcwaitClusterOperationCompleted(ctxcontext.Context,conn*kafka.Kafka,arnstring,timeouttime.Duration)(*kafka.ClusterOperationInfo,error){//nolint:unparamstateConf:=&retry.StateChangeConf{Pending:[]string{ClusterOperationStatePending,ClusterOperationStateUpdateInProgress},Target:[]string{ClusterOperationStateUpdateComplete},Refresh:statusClusterOperationState(ctx,conn,arn),Timeout:timeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*kafka.ClusterOperationInfo);ok{ifstate,errorInfo:=aws.StringValue(output.OperationState),output.ErrorInfo;state==ClusterOperationStateUpdateFailed&&errorInfo!=nil{tfresource.SetLastError(err,fmt.Errorf("%s:%s",aws.StringValue(errorInfo.ErrorCode),aws.StringValue(errorInfo.ErrorString)))}returnoutput,err}returnnil,err}funcwaitConfigurationDeleted(ctxcontext.Context,conn*kafka.Kafka,arnstring)(*kafka.DescribeConfigurationOutput,error){stateConf:=&retry.StateChangeConf{Pending:[]string{kafka.ConfigurationStateDeleting},Target:[]string{},Refresh:statusConfigurationState(ctx,conn,arn),Timeout:configurationDeletedTimeout,}outputRaw,err:=stateConf.WaitForStateContext(ctx)ifoutput,ok:=outputRaw.(*kafka.DescribeConfigurationOutput);ok{returnoutput,err}returnnil,err}